import React, { useState, useEffect, useCallback } from 'react';
import { enquiryAPI } from '../services/api';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';

const STATUS_CFG = {
  new:       { bg:'#DBEAFE', c:'#1E40AF', label:'🆕 New'        },
  hot:       { bg:'#FEE2E2', c:'#991B1B', label:'🔥 Hot Lead'   },
  warm:      { bg:'#FEF3C7', c:'#92400E', label:'🌡️ Warm Lead'  },
  cold:      { bg:'#F3F4F6', c:'#374151', label:'🧊 Cold Lead'  },
  converted: { bg:'#D1FAE5', c:'#065F46', label:'✅ Converted'  },
  cancelled: { bg:'#F3F4F6', c:'#9CA3AF', label:'❌ Cancelled'  },
};
const SOURCES = ['walk_in','phone','website','reference','social_media','newspaper'];
const CLASSES = ['Class 1','Class 2','Class 3','Class 4','Class 5','Class 6','Class 7','Class 8','Class 9','Class 10','Class 11','Class 12'];
const inp = { width:'100%', padding:'10px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', fontFamily:'inherit', background:'#fff', boxSizing:'border-box' };
const lbl = { display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 };

export default function Enquiry() {
  const navigate = useNavigate();
  const [enquiries, setEnquiries] = useState([]);
  const [loading,   setLoading]   = useState(true);
  const [isMock,    setIsMock]    = useState(false);
  const [total,     setTotal]     = useState(0);
  const [filter,    setFilter]    = useState('');
  const [search,    setSearch]    = useState('');
  const [selected,  setSelected]  = useState(null);
  const [showAdd,   setShowAdd]   = useState(false);
  const [saving,    setSaving]    = useState(false);
  const [form, setForm] = useState({ name:'', parent:'', phone:'', email:'', class_:'', source:'walk_in', remarks:'', status:'warm' });

  const MOCK = [
    { id:1, enquiry_no:'ENQ001', student_name:'Riya Gupta',   parent_name:'Sanjay Gupta',  mobile:'9811001100', class_interested:'Class 6',  source:'walk_in', created_at:'2025-06-05', status:'hot',  remarks:'Very interested' },
    { id:2, enquiry_no:'ENQ002', student_name:'Rahul Sharma', parent_name:'Amit Sharma',   mobile:'9822002200', class_interested:'Class 9',  source:'phone',   created_at:'2025-06-04', status:'warm', remarks:'Wants demo class' },
    { id:3, enquiry_no:'ENQ003', student_name:'Pooja Verma',  parent_name:'Dinesh Verma',  mobile:'9833003300', class_interested:'Class 7',  source:'reference',created_at:'2025-06-03', status:'hot',  remarks:'Referred by parent' },
    { id:4, enquiry_no:'ENQ004', student_name:'Akash Yadav',  parent_name:'Suresh Yadav',  mobile:'9844004400', class_interested:'Class 11', source:'website',  created_at:'2025-06-02', status:'cold', remarks:'Just checking' },
    { id:5, enquiry_no:'ENQ005', student_name:'Sneha Pandey', parent_name:'Vijay Pandey',  mobile:'9855005500', class_interested:'Class 8',  source:'walk_in',  created_at:'2025-06-01', status:'warm', remarks:'Visit requested' },
  ];

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await enquiryAPI.getAll({ status: filter || undefined, search: search || undefined });
      setEnquiries(res.data.data || []);
      setTotal(res.data.pagination?.total || 0);
      setIsMock(false);
    } catch {
      let d = [...MOCK];
      if (filter) d = d.filter(e => e.status === filter);
      if (search) d = d.filter(e => e.student_name.toLowerCase().includes(search.toLowerCase()) || e.mobile.includes(search));
      setEnquiries(d); setTotal(d.length); setIsMock(true);
    } finally { setLoading(false); }
  }, [filter, search]);

  useEffect(() => { load(); }, [load]);

  const handleAdd = async (e) => {
    e.preventDefault(); setSaving(true);
    try {
      await enquiryAPI.create({ studentName:form.name, parentName:form.parent, mobile:form.phone, email:form.email||undefined, classInterested:form.class_||undefined, source:form.source, remarks:form.remarks, status:form.status });
      toast.success('✅ Enquiry saved to database!');
      setShowAdd(false);
      setForm({ name:'', parent:'', phone:'', email:'', class_:'', source:'walk_in', remarks:'', status:'warm' });
      load();
    } catch {
      toast.success('Enquiry added (demo mode)');
      const mock = { id:Date.now(), enquiry_no:`ENQ${String(enquiries.length+1).padStart(3,'0')}`, student_name:form.name, parent_name:form.parent, mobile:form.phone, class_interested:form.class_, source:form.source, created_at:new Date().toISOString().split('T')[0], status:form.status, remarks:form.remarks };
      setEnquiries(p=>[mock,...p]); setShowAdd(false); setIsMock(true);
    } finally { setSaving(false); }
  };

  const handleStatusChange = async (id, status) => {
    try {
      await enquiryAPI.update(id, { status });
      setEnquiries(p => p.map(e => e.id===id ? {...e, status} : e));
      toast.success(`Status updated to ${STATUS_CFG[status]?.label}`);
    } catch {
      setEnquiries(p => p.map(e => e.id===id ? {...e, status} : e));
    }
  };

  const handleConvert = async (enq) => {
    try {
      await enquiryAPI.update(enq.id, { status:'converted' });
      toast.success(`✅ ${enq.student_name} converted! Now add in Registration.`);
      setEnquiries(p => p.map(e => e.id===enq.id ? {...e, status:'converted'} : e));
      setSelected(null);
      setTimeout(() => navigate('/registration'), 1200);
    } catch {
      toast.success('Converted to registration (demo)');
      setSelected(null); navigate('/registration');
    }
  };

  const counts = Object.fromEntries(Object.keys(STATUS_CFG).map(k=>[k, enquiries.filter(e=>e.status===k).length]));

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Enquiry Management</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>
            {total} enquiries
            {isMock ? <span style={{marginLeft:8,padding:'2px 8px',background:'#FEF3C7',color:'#92400E',borderRadius:10,fontSize:10,fontWeight:700}}>Demo mode</span>
                    : <span style={{marginLeft:8,padding:'2px 8px',background:'#D1FAE5',color:'#065F46',borderRadius:10,fontSize:10,fontWeight:700}}>🟢 Live DB</span>}
          </p>
        </div>
        <button onClick={()=>setShowAdd(true)} style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ New Enquiry</button>
      </div>

      {/* Pipeline */}
      <div style={{display:'flex',alignItems:'center',gap:8,padding:'10px 14px',background:'#EDE9F8',borderRadius:10,marginBottom:14,fontSize:12,color:'#1E1B4B',fontWeight:600}}>
        <span style={{fontWeight:800,textDecoration:'underline'}}>📞 Enquiry</span>
        <span style={{color:'#A78BFA',fontSize:16}}>→</span>
        <span>📄 Registration</span>
        <span style={{color:'#A78BFA',fontSize:16}}>→</span>
        <span>🎓 Admission (Students)</span>
      </div>

      {/* Status pills */}
      <div style={{display:'flex',gap:8,marginBottom:14,flexWrap:'wrap',alignItems:'center'}}>
        <input placeholder="🔍 Search name or phone…" value={search} onChange={e=>setSearch(e.target.value)}
          style={{...inp,maxWidth:220,flex:1,padding:'8px 12px'}}/>
        {Object.entries(STATUS_CFG).map(([key,{bg,c,label}])=>(
          <div key={key} onClick={()=>setFilter(filter===key?'':key)}
            style={{padding:'6px 12px',borderRadius:20,background:filter===key?c:bg,color:filter===key?'#fff':c,fontSize:11,fontWeight:700,cursor:'pointer',border:`1.5px solid ${c}33`,userSelect:'none'}}>
            {label} ({counts[key]||0})
          </div>
        ))}
      </div>

      {/* Table */}
      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
          <thead><tr style={{background:'#F9FAFB'}}>
            {['Enq No','Student','Parent / Phone','Class','Source','Date','Status','Action'].map(h=>(
              <th key={h} style={{padding:'10px 12px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:700,textTransform:'uppercase',borderBottom:'1px solid #E5E7EB',whiteSpace:'nowrap'}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>
            {loading && <tr><td colSpan={8} style={{padding:36,textAlign:'center',color:'#9CA3AF'}}>⏳ Loading…</td></tr>}
            {!loading && enquiries.length===0 && <tr><td colSpan={8} style={{padding:48,textAlign:'center',color:'#9CA3AF'}}>
              <div style={{fontSize:36,marginBottom:8}}>📞</div>No enquiries yet
            </td></tr>}
            {!loading && enquiries.map(e=>{
              const st = STATUS_CFG[e.status] || STATUS_CFG.new;
              return (
                <tr key={e.id} style={{borderBottom:'0.5px solid #F3F4F6',transition:'background .1s'}}
                  onMouseEnter={ev=>ev.currentTarget.style.background='#F5F3FF'}
                  onMouseLeave={ev=>ev.currentTarget.style.background=''}>
                  <td style={{padding:'10px 12px',fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{e.enquiry_no}</td>
                  <td style={{padding:'10px 12px',fontWeight:700,color:'#111827'}}>{e.student_name}</td>
                  <td style={{padding:'10px 12px'}}><div style={{fontWeight:500}}>{e.parent_name}</div><div style={{fontSize:10,color:'#9CA3AF'}}>{e.mobile}</div></td>
                  <td style={{padding:'10px 12px',color:'#6B7280'}}>{e.class_interested||'—'}</td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#EDE9F8',color:'#1E1B4B',fontWeight:600}}>{(e.source||'').replace('_',' ')}</span></td>
                  <td style={{padding:'10px 12px',color:'#6B7280',fontSize:11}}>{e.created_at?.split('T')[0]}</td>
                  <td style={{padding:'10px 12px'}}>
                    {e.status!=='converted' ? (
                      <select value={e.status} onChange={ev=>handleStatusChange(e.id,ev.target.value)}
                        style={{padding:'4px 8px',border:'1px solid #E5E7EB',borderRadius:7,fontSize:11,background:'#fff',outline:'none',cursor:'pointer'}}>
                        {Object.entries(STATUS_CFG).filter(([k])=>k!=='converted').map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
                      </select>
                    ) : <span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:700,background:st.bg,color:st.c}}>{st.label}</span>}
                  </td>
                  <td style={{padding:'10px 12px'}}>
                    <button onClick={()=>setSelected(e)} style={{padding:'5px 12px',border:'1px solid #1E1B4B',borderRadius:7,background:'#EDE9F8',color:'#1E1B4B',fontSize:11,fontWeight:600,cursor:'pointer'}}>Details</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        <div style={{padding:'9px 14px',borderTop:'0.5px solid #E5E7EB',fontSize:11,color:'#6B7280'}}>{total} total enquiries</div>
      </div>

      {/* Detail modal */}
      {selected&&(
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:400,display:'flex',alignItems:'center',justifyContent:'center',padding:20}}>
          <div style={{background:'#fff',borderRadius:18,width:480,maxHeight:'90vh',overflow:'auto'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center',position:'sticky',top:0,background:'#fff'}}>
              <div style={{fontWeight:700,fontSize:15}}>Enquiry — {selected.enquiry_no}</div>
              <button onClick={()=>setSelected(null)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <div style={{padding:20}}>
              <div style={{padding:14,background:(STATUS_CFG[selected.status]||STATUS_CFG.new).bg,borderRadius:10,marginBottom:16,display:'flex',justifyContent:'space-between',alignItems:'center'}}>
                <span style={{fontWeight:700,color:(STATUS_CFG[selected.status]||STATUS_CFG.new).c,fontSize:14}}>{(STATUS_CFG[selected.status]||STATUS_CFG.new).label}</span>
                <span style={{fontSize:11,color:(STATUS_CFG[selected.status]||STATUS_CFG.new).c}}>#{selected.enquiry_no}</span>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:14}}>
                {[['Student',selected.student_name],['Parent',selected.parent_name],['Mobile',selected.mobile],['Email',selected.email||'—'],['Class Interested',selected.class_interested||'—'],['Source',(selected.source||'').replace('_',' ')],['Date',selected.created_at?.split('T')[0]],['Status',selected.status]].map(([k,v])=>(
                  <div key={k} style={{padding:'9px 12px',background:'#F9FAFB',borderRadius:9}}>
                    <div style={{fontSize:10,color:'#9CA3AF',fontWeight:700,textTransform:'uppercase',marginBottom:3}}>{k}</div>
                    <div style={{fontSize:13,fontWeight:600,color:'#111827'}}>{v}</div>
                  </div>
                ))}
              </div>
              {selected.remarks&&<div style={{padding:'10px 12px',background:'#FEF3C7',borderRadius:9,marginBottom:16,fontSize:12,color:'#92400E'}}><strong>Remarks:</strong> {selected.remarks}</div>}
              {selected.status!=='converted' ? (
                <div style={{display:'flex',gap:10}}>
                  <button onClick={()=>handleConvert(selected)} style={{flex:1,padding:'11px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:10,fontSize:13,fontWeight:700,cursor:'pointer'}}>📄 Convert to Registration →</button>
                  <button onClick={()=>{toast.success('Follow-up scheduled!');setSelected(null);}} style={{padding:'11px 14px',border:'1.5px solid #E5E7EB',borderRadius:10,background:'#fff',fontSize:12,cursor:'pointer'}}>📅 Follow-up</button>
                </div>
              ):(
                <div style={{padding:14,background:'#D1FAE5',borderRadius:10,textAlign:'center',color:'#065F46',fontWeight:600,fontSize:13}}>
                  ✅ Converted to Registration
                  <button onClick={()=>{navigate('/registration');setSelected(null);}} style={{display:'block',margin:'8px auto 0',padding:'6px 16px',background:'#065F46',color:'#fff',border:'none',borderRadius:7,fontSize:12,cursor:'pointer'}}>View in Registration →</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Add modal */}
      {showAdd&&(
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:520,maxWidth:'100%',maxHeight:'90vh',overflow:'auto'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center',position:'sticky',top:0,background:'#fff'}}>
              <div style={{fontWeight:700,fontSize:15}}>📞 New Enquiry</div>
              <button onClick={()=>setShowAdd(false)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <form onSubmit={handleAdd} style={{padding:20}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Student Name *</label><input required value={form.name} onChange={e=>setForm({...form,name:e.target.value})} placeholder="Full name" style={inp} autoFocus/></div>
                <div><label style={lbl}>Parent Name *</label><input required value={form.parent} onChange={e=>setForm({...form,parent:e.target.value})} placeholder="Parent name" style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Mobile *</label><input required value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})} placeholder="10-digit" maxLength={10} style={inp}/></div>
                <div><label style={lbl}>Email</label><input type="email" value={form.email} onChange={e=>setForm({...form,email:e.target.value})} placeholder="optional" style={inp}/></div>
                <div><label style={lbl}>Class Interested</label><select value={form.class_} onChange={e=>setForm({...form,class_:e.target.value})} style={inp}><option value="">Select</option>{CLASSES.map(c=><option key={c}>{c}</option>)}</select></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Source</label><select value={form.source} onChange={e=>setForm({...form,source:e.target.value})} style={inp}>{SOURCES.map(s=><option key={s} value={s}>{s.replace(/_/g,' ')}</option>)}</select></div>
                <div><label style={lbl}>Lead Status</label><select value={form.status} onChange={e=>setForm({...form,status:e.target.value})} style={inp}>{Object.entries(STATUS_CFG).filter(([k])=>k!=='converted').map(([k,v])=><option key={k} value={k}>{v.label}</option>)}</select></div>
              </div>
              <div style={{marginBottom:16}}><label style={lbl}>Remarks</label><textarea value={form.remarks} onChange={e=>setForm({...form,remarks:e.target.value})} placeholder="Notes…" rows={3} style={{...inp,resize:'vertical'}}/></div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button type="button" onClick={()=>setShowAdd(false)} style={{padding:'10px 18px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" disabled={saving} style={{padding:'10px 22px',background:saving?'#9CA3AF':'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>
                  {saving?'⏳ Saving…':'💾 Save Enquiry'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
